fn iter_u8_new(base: u64, len: u64) -> u64 @export {
    if base == 0u64 && len != 0u64 { return ITER_INVALID }
    let mut i : u32 = 0u32
    let mut slot : u32 = 0xFFFFFFFFu32
    while i < ITER_MAX {
        if ITER_LIVE[i] == 0u8 {
            if slot == 0xFFFFFFFFu32 { slot = i }
        }
        i = i + 1u32
    }
    if slot == 0xFFFFFFFFu32 { return ITER_INVALID }
    ITER_BASE[slot] = base
    ITER_LEN[slot]  = len
    ITER_POS[slot]  = 0u64
    ITER_LIVE[slot] = 1u8
    return (slot as u64) + 1u64
}

