/* 1023 — omnia::iter null-base construction guard.
 *
 * Proves the fix fires on bad input:
 *   iter_u8_new(0, 5)   must return ITER_INVALID (0)  -- NULL base, non-zero len
 *   iter_u8_new(0, 0)   must return non-zero          -- NULL base, zero len is OK
 *   iter_u8_new(p, 3)   must work normally             -- positive case unchanged
 *
 * Exit 99 = pass.
 */
module corpus_1023_iter_null_base_guard

extern @abi(c-msvc-x64) fn malloc(n: u64) -> *u8 from "msvcrt"
extern @abi(c-msvc-x64) fn free(p: *u8) -> u64 from "msvcrt"
extern @abi(c-msvc-x64) fn iter_u8_new(base: u64, len: u64) -> u64 from "iter.iii"
extern @abi(c-msvc-x64) fn iter_u8_next(id: u64) -> u32 from "iter.iii"
extern @abi(c-msvc-x64) fn iter_u8_drop(id: u64) -> u8 from "iter.iii"

fn main() -> u64 {
    /* NEGATIVE: null base with non-zero len must return ITER_INVALID (0). */
    let bad : u64 = iter_u8_new(0u64, 5u64)
    if bad != 0u64 { return 1u64 }

    /* BOUNDARY: null base with zero len is a valid empty iterator. */
    let empty : u64 = iter_u8_new(0u64, 0u64)
    if empty == 0u64 { return 2u64 }
    /* An empty iterator must signal exhaustion immediately. */
    if iter_u8_next(empty) != 0x100u32 { return 3u64 }
    iter_u8_drop(empty)

    /* POSITIVE: normal case must still work. */
    let p : *u8 = malloc(3u64)
    if p as u64 == 0u64 { return 4u64 }
    p[0] = 10u8
    p[1] = 20u8
    p[2] = 30u8
    let it : u64 = iter_u8_new(p as u64, 3u64)
    if it == 0u64 { free(p); return 5u64 }
    if iter_u8_next(it) != 10u32 { free(p); return 6u64 }
    if iter_u8_next(it) != 20u32 { free(p); return 7u64 }
    if iter_u8_next(it) != 30u32 { free(p); return 8u64 }
    if iter_u8_next(it) != 0x100u32 { free(p); return 9u64 }
    iter_u8_drop(it)
    free(p)
    return 99u64
}
